SELECT "RECEIVED" AS LineStatus, Item.[Trademark Code], Item.[Collection Code], Item.[Season Code], Item.[Line Code] AS LineCode, Item.[Product Family], Item.[Product Sex], Item.[Model Item No_] AS Article, [Purch_ Rcpt_ Line].[Variable Code 01] AS Color, [Purchase Line].[Promised Receipt Date] AS PromisedReceiptDate, [Purchase Line].[Requested Receipt Date] AS RequestedReceiptDate, [Purchase Line].[Planned Receipt Date] AS PlannedReceiptDate, [Purch_ Rcpt_ Header].[Posting Date] AS ReceiptDate, [Purch_ Rcpt_ Header].No_ AS ReceiptNumber, [Purchase Line].[Document No_] AS OrderNumber, [Purchase Line].[Line No_] AS OrderLine, [Purchase Header].[Vendor Order No_] AS VendorOrderNr, AnalisiDateConsegnaDatoAssortimenti.AssortmentCode, Val([Purch_ Rcpt_ Line.Quantity (Base)]) AS ReceiptQuantity, Val([Purchase Line.Line Amount])/Val([Purchase Line.quantity])*Val([Purch_ Rcpt_ Line.quantity]) AS ReceiptValue, [Purchase Line].[Document Type], [Purchase Line].[Delete Reason], Item.[Description 2], [Purchase Line].[Sales_Purchase Status Code] AS CodStatusVendAcq, [Purchase Line].[Sales_Purchase Status - Item] AS CodStatusVendAcqArticolo, Item.[Sold Out], Item.[Sold Out Date], Item.[Sales_Purchase Status Date], [Purch_ Rcpt_ Header].[Vendor Shipment No_], Item.Manufacturer AS ManufacturerCode, Item.[advertising material]
FROM ((([Purch_ Rcpt_ Line] INNER JOIN [Purch_ Rcpt_ Header] ON [Purch_ Rcpt_ Line].[Document No_] = [Purch_ Rcpt_ Header].No_) INNER JOIN ([Purchase Line] INNER JOIN Item ON [Purchase Line].No_ = Item.No_) ON ([Purch_ Rcpt_ Line].[Order No_] = [Purchase Line].[Document No_]) AND ([Purch_ Rcpt_ Line].[Order Line No_] = [Purchase Line].[Line No_])) INNER JOIN AnalisiDateConsegnaDatoAssortimenti ON ([Purchase Line].[Original Line No_] = AnalisiDateConsegnaDatoAssortimenti.[Line No_]) AND ([Purchase Line].[Document No_] = AnalisiDateConsegnaDatoAssortimenti.[Document No_])) INNER JOIN [Purchase Header] ON [Purchase Line].[Document No_] = [Purchase Header].No_
WHERE (((Item.[Season Code])=[filtroStagione]) AND ((Val([Purch_ Rcpt_ Line.Quantity (Base)]))<>0) AND (([Purchase Line].[Document Type])=1) AND (([Purchase Line].Type)=2));

